SELECT p.player_name, t.team_name, p.goals_scored AS total_goals_scored
FROM players p
INNER JOIN teams t ON p.team_id = t.team_id;

SELECT SUM(minutes_played) AS Total_Minutes
FROM player_stats
WHERE player_id = 'desired_player_id';

SELECT player_id, AVG(points) AS typical_score
FROM fantasy_points
GROUP BY player_id;

SELECT COUNT(*) 
FROM players 
WHERE age > 30 AND goals_scored > 10;

SELECT p.player_name, t.team_name, p.age, p.nationality, p.goals_scored AS Total_Goals, p.yellow_cards AS Total_Yellow_Cards
FROM players p
JOIN teams t ON p.team_id = t.team_id;

SELECT player_name 
FROM players 
WHERE player_id IN (SELECT player_id FROM expert_ratings);

SELECT COUNT(comment_id) AS total_comments
FROM comments
WHERE player_id = 100;
